const features = $json.features || [];
const usable = features
  .filter((f) => f.geometry && Array.isArray(f.geometry.coordinates))
  .sort((a, b) => (b.properties?.mag || 0) - (a.properties?.mag || 0));

if (!usable.length) {
  throw new Error('No usable USGS event returned.');
}

const selected = usable[0];
const [longitude, latitude, depthKm] = selected.geometry.coordinates;
const props = selected.properties || {};

return [
  {
    json: {
      disaster: {
        source: 'usgs_earthquake_significant_month',
        id: selected.id,
        title: props.title || 'USGS earthquake event',
        url: props.url,
        occurred_at: props.time ? new Date(props.time).toISOString() : null,
        latitude,
        longitude,
        depth_km: depthKm,
        magnitude: props.mag,
        place: props.place,
        event_type: props.type || 'earthquake'
      },
      feral_intent: {
        project: 'feral',
        mode: 'Disaster-to-Feral + Habitat Mapper + RAG + Hermes Review',
        art_direction: 'hyperreal animal-viewpoint disaster ecology, near-future speculative realism'
      },
      rag_keywords: `${props.title || 'earthquake'} ${props.place || 'disaster'}`.toLowerCase().replace(/[^a-z0-9 ]/g, ' ').trim()
    }
  }
];

const ingestResult = $('feral Sidecar Ingest').item.json;
const ragResult = $('RAG Knowledge Search').item.json;
const hermesResult = $('Hermes Review').item.json;

const packet = {
  run_id: ingestResult.run_id,
  created_at: new Date().toISOString(),
  feral_ingest: {
    prompt_packet_path: ingestResult.prompt_packet_path,
    positive_prompt: ingestResult.positive_prompt,
    negative_prompt: ingestResult.negative_prompt,
    habitat_feature_count: ingestResult.habitat_feature_count
  },
  rag_knowledge: {
    query: ragResult.query,
    results: (ragResult.results || []).slice(0, 3).map(r => ({
      run_id: r.run_id,
      score: r.score,
      prompt_snippet: (r.positive_prompt || '').slice(0, 200)
    }))
  },
  hermes_review: hermesResult,
  status: 'e2e_scaffold_complete'
};

return [{ json: packet }];

const packet = $json;
const fs = require('fs');
const path = require('path');

const outputDir = '/media/kz003/atelier/feral/outputs/runs/' + packet.run_id;
if (!fs.existsSync(outputDir)) {
  fs.mkdirSync(outputDir, { recursive: true });
}

const outputPath = path.join(outputDir, 'e2e-scaffold-packet.json');
fs.writeFileSync(outputPath, JSON.stringify(packet, null, 2), 'utf-8');

return [{
  json: {
    run_id: packet.run_id,
    output_path: outputPath,
    status: packet.status,
    summary: `Feral E2E scaffold complete. Prompt: ${packet.feral_ingest?.positive_prompt?.slice(0, 100)}...`
  }
}];
